select datetime, delta, error
from (
    select datetime, delta, error
    from appmon_event_count_hourly
    where domain = #{domain} and instance = #{instance} and event = #{event}

        and datetime < #{dateOffset}

    order by datetime desc
)
where rownum <= 100
order by 1

