choose.when:
select datetime, delta, error
from (
    select min(datetime) as datetime, sum(delta) as delta, sum(error) as error
    from (
        select datetime, delta, error
        from appmon_event_count_hourly
        where domain = #{domain} and instance = #{instance} and event = #{event}

            and datetime < #{dateOffset}

        order by datetime desc
    )
    where rownum <= 3000
    group by trunc(datetime + #{zoneOffset} / 86400.0)
    order by 1 desc
)
where rownum <= 100
order by 1

select datetime, delta, error
from (
    select min(datetime) as datetime, sum(delta) as delta, sum(error) as error
    from (
        select datetime, delta, error
        from appmon_event_count_hourly
        where domain = #{domain} and instance = #{instance} and event = #{event}

            and datetime < #{dateOffset}

        order by datetime desc
        limit 3000
    ) as raw
    group by date(date_add(datetime, interval #{zoneOffset} second))
    order by 1 desc
    limit 100
) as x
order by 1

select datetime, delta, error
from (
    select min(datetime) as datetime, sum(delta) as delta, sum(error) as error
    from (
        select datetime, delta, error
        from appmon_event_count_hourly
        where domain = #{domain} and instance = #{instance} and event = #{event}

            and datetime < #{dateOffset}

        order by datetime desc
        limit 3000
    ) as raw
    group by date_trunc('day', datetime + (#{zoneOffset} || ' second')::interval)
    order by 1 desc
    limit 100
) as x
order by 1

choose.otherwise:
select datetime, delta, error
from (
    select min(datetime) as datetime, sum(delta) as delta, sum(error) as error
    from (
        select datetime, delta, error
        from appmon_event_count_hourly
        where domain = #{domain} and instance = #{instance} and event = #{event}

            and datetime < #{dateOffset}

        order by datetime desc
        limit 3000
    ) as raw
    group by cast(dateadd(second, #{zoneOffset}, datetime) as date)
    order by 1 desc
    limit 100
) as x
order by 1

